def run(value_list):
    # Filter for internet service customers net additions (losses) for 2019 and 2018
    net_additions_2019 = next((item['number_value'] for item in value_list if item['category'] == 'Internet service customers' and item['header1'] == 'August 31, 2019' and item['header2'] == 'Net additions (losses)'), 0)
    net_additions_2018 = next((item['number_value'] for item in value_list if item['category'] == 'Internet service customers' and item['header1'] == 'August 31, 2018 (1)' and item['header2'] == 'Net additions (losses)'), 0)

    # Calculate average increase / (decrease)
    average_increase_decrease = (net_additions_2019 - net_additions_2018) / 2

    # Determine scale
    if abs(average_increase_decrease) >= 1e6:
        scale = 'million'
    elif abs(average_increase_decrease) >= 1e3:
        scale = 'thousand'
    elif abs(average_increase_decrease) >= 1:
        scale = ''
    else:
        scale = 'percent'

    # Format number to two decimal places
    number = round(average_increase_decrease, 2)

    return (number, scale)

def run(value_list):
    direct_2018 = None
    direct_2019 = None
    for item in value_list:
        if item['category'] == 'Direct energy consumption (MWh)':
            if item['header1'] == '2018':
                direct_2018 = item['number_value']
            elif item['header1'] == '2019':
                direct_2019 = item['number_value']
    if direct_2018 is None or direct_2019 is None:
        return (0.0, '')
    change = direct_2019 - direct_2018
    percentage_change = (change / direct_2018) * 100
    if abs(percentage_change) > 100:
        return (change, 'billion')
    elif abs(percentage_change) > 10:
        return (change, 'million')
    elif abs(percentage_change) > 1:
        return (percentage_change, 'percent')
    else:
        return (change, '')

